const _stretchX = 1.16;
const _mapVbW = 788 * _stretchX; // ~914
const _mapVbH = 609.0;
const _margin = 34.0;
const _fullW = _mapVbW + _margin * 2;
const _fullH = _mapVbH + _margin * 2;
const _rawCenter = Offset(391.8, 298.8);
final _mapCenter = Offset(_rawCenter.dx * _stretchX, _rawCenter.dy);
const _rawMarker = <int, List<double>>{
  1: [392, 98], 2: [504, 96], 3: [575, 161], 4: [667, 213], 5: [665, 299], 6: [660, 382],
  7: [571, 433], 8: [505, 503], 9: [392, 506], 10: [282, 498], 11: [207, 438], 12: [114, 385],
  13: [122, 299], 14: [121, 214], 15: [211, 162], 16: [279, 94],
};
const _markerR = 32.0;
class _Lily {
  final double x, y, r;
  const _Lily(this.x, this.y, this.r);
}

final _lilies = <_Lily>[
  _Lily(_mapCenter.dx - 118, _mapCenter.dy - 70, 15),
  _Lily(_mapCenter.dx + 96, _mapCenter.dy - 40, 12),
  _Lily(_mapCenter.dx - 40, _mapCenter.dy + 100, 13),
  _Lily(_mapCenter.dx + 130, _mapCenter.dy + 60, 10),
  _Lily(_mapCenter.dx - 150, _mapCenter.dy + 20, 9),
];

Map<int, Offset> _computeMarkers() {
  final out = <int, Offset>{};
  _rawMarker.forEach((n, xy) {
    final dx = (xy[0] - _rawCenter.dx) * _stretchX;
    final dy = (xy[1] - _rawCenter.dy);
    out[n] = Offset(_mapCenter.dx + dx, _mapCenter.dy + dy);
  });
  return out;
}

