/// Точка на берегу ровно между двумя соседними секторами — для кустов/камышей.
Offset _midBankPoint(int n1, int n2, [double push = 6]) {
  final p1 = _markerPos[n1]!, p2 = _markerPos[n2]!;
  final mx = (p1.dx + p2.dx) / 2, my = (p1.dy + p2.dy) / 2;
  final dx = mx - _mapCenter.dx, dy = my - _mapCenter.dy;
  final len = math.sqrt(dx * dx + dy * dy);
  final k = len == 0 ? 0.0 : push / len;
  return Offset(mx + dx * k, my + dy * k);
}

// ─────────────────────────── Painter карты пруда ───────────────────────────
class _PondPainter extends CustomPainter {
  final Map<int, String> statusByNumber;
  final int? selected;
  final List<ui.Image?> treeImages; // 4 варианта дерева
  final ui.Image? grassTile;
  _PondPainter({
    required this.statusByNumber,
    required this.selected,
    required this.treeImages,
    required this.grassTile,
  });

  @override
  void paint(Canvas canvas, Size size) {
    final scale = size.width / _fullW;
    canvas.save();
    canvas.scale(scale);

    final fullRect = const Rect.fromLTWH(0, 0, _fullW, _fullH);
    final rrect = RRect.fromRectAndRadius(fullRect, const Radius.circular(26));

    // фон-трава (градиент)
    canvas.drawRRect(
      rrect,
      Paint()
        ..shader = const RadialGradient(
          center: Alignment(0, -0.24),
          radius: 0.78,
          colors: [Color(0xFF548F5F), Color(0xFF3F7C4A), Color(0xFF2A5533)],
          stops: [0, 0.45, 1],
        ).createShader(fullRect),
    );

    // реальная фото-текстура травы поверх градиента (как в референсе — 2 слоя с opacity)
    if (grassTile != null) {
      canvas.save();
      canvas.clipRRect(rrect);
      canvas.saveLayer(fullRect, Paint()..color = Colors.white.withOpacity(0.55));
      final tileShader = ImageShader(
        grassTile!, TileMode.repeated, TileMode.repeated, Matrix4.identity().storage,
      );
      canvas.drawRect(fullRect, Paint()..shader = tileShader);
      canvas.restore();
      canvas.restore();
    }
    canvas.saveLayer(fullRect, Paint()..color = Colors.white.withOpacity(0.35));
    canvas.drawRRect(
      rrect,
      Paint()
        ..shader = const RadialGradient(
          center: Alignment(0, -0.24),
          radius: 0.78,
          colors: [Color(0xFF548F5F), Color(0xFF3F7C4A), Color(0xFF2A5533)],
          stops: [0, 0.45, 1],
        ).createShader(fullRect),
    );
    canvas.restore();

    // густой лес по периметру — 4 варианта дерева, лёгкий случайный поворот
    for (var i = 0; i < _forestSpots.length; i++) {
      final s = _forestSpots[i];
      final cx = s[0] * _fullW, cy = s[1] * _fullH;
      final imgIdx = s[2].round();
      final treeSize = 92 * s[3];
      final img = treeImages.length > imgIdx ? treeImages[imgIdx] : null;
      if (img == null) continue;
      final rot = (i * 47 % 360) * math.pi / 180;

      canvas.drawOval(
        Rect.fromCenter(center: Offset(cx, cy + treeSize * 0.36), width: treeSize * 0.72, height: treeSize * 0.24),
        Paint()..color = Colors.black.withOpacity(0.16),
      );
      canvas.save();
      canvas.translate(cx, cy);
      canvas.rotate(rot);
      final src = Rect.fromLTWH(0, 0, img.width.toDouble(), img.height.toDouble());
      final dst = Rect.fromCenter(center: Offset.zero, width: treeSize, height: treeSize);
      canvas.drawImageRect(img, src, dst, Paint()..filterQuality = FilterQuality.medium);
      canvas.restore();
    }

    canvas.translate(_margin, _margin);

    // Путь берега / воды
    final outer = _catmullRomPath(_offsetPoints(16));
    final water = _catmullRomPath(_offsetPoints(-14));

    // дорожка
    canvas.drawPath(outer, Paint()
      ..shader = const LinearGradient(
        colors: [Color(0xFFE4C486), Color(0xFFCE9F57), Color(0xFFB4874A)],
        stops: [0, 0.55, 1],
      ).createShader(const Rect.fromLTWH(0, 0, _mapVbW, _mapVbH)));
    canvas.drawPath(outer, Paint()
      ..style = PaintingStyle.stroke
      ..strokeWidth = 1
      ..color = Colors.black.withOpacity(0.13));

    // короткие прибрежные тростники у кромки воды (фикс. точки, как в референсе)
    _drawReedTuft(canvas, Offset(_mapCenter.dx - 150, _mapCenter.dy - 150), 0.55);
    _drawReedTuft(canvas, Offset(_mapCenter.dx + 170, _mapCenter.dy - 120), 0.5);

    // кусты и камыши вдоль берега между секторами (зона причала/удочек не занята)
    _drawBush(canvas, _midBankPoint(2, 3), 0.6, 1);
    _drawBush(canvas, _midBankPoint(6, 7), 0.55, 0);
    _drawBush(canvas, _midBankPoint(11, 12), 0.6, 2);
    _drawBush(canvas, _midBankPoint(14, 15), 0.52, 1);
    _drawReedTuft(canvas, _midBankPoint(4, 5), 0.75);
    _drawReedTuft(canvas, _midBankPoint(12, 13), 0.7);
    _drawReedTuft(canvas, _midBankPoint(15, 16), 0.68);

    // вода
    canvas.drawPath(water, Paint()
      ..shader = const RadialGradient(
        center: Alignment(-0.24, -0.36),
        radius: 0.75,
        colors: [Color(0xFF4AA0C6), Color(0xFF2A7E9E), Color(0xFF186286), Color(0xFF0F4C6C)],
        stops: [0, 0.35, 0.7, 1],
      ).createShader(const Rect.fromLTWH(0, 0, _mapVbW, _mapVbH)));

    // блики, рябь и лилии — всё клипуется по форме воды
    canvas.save();
    canvas.clipPath(water);
    canvas.drawOval(
      Rect.fromCenter(center: Offset(_mapCenter.dx - 70, _mapCenter.dy - 90), width: 320, height: 140),
      Paint()
        ..shader = RadialGradient(
          colors: [Colors.white.withOpacity(0.5), Colors.white.withOpacity(0)],
        ).createShader(Rect.fromCenter(center: Offset(_mapCenter.dx - 70, _mapCenter.dy - 90), width: 320, height: 140)),
    );
    canvas.drawOval(
      Rect.fromCenter(center: Offset(_mapCenter.dx + 120, _mapCenter.dy + 60), width: 180, height: 80),
      Paint()..color = Colors.white.withOpacity(0.05),
    );
    for (var i = 0; i < 3; i++) {
      canvas.drawOval(
        Rect.fromCenter(
          center: Offset(_mapCenter.dx - 30 + i * 70, _mapCenter.dy + 130),
          width: (70 - i * 10) * 2, height: 12,
        ),
        Paint()
          ..style = PaintingStyle.stroke
          ..strokeWidth = 1
          ..color = Colors.white.withOpacity(0.12),
      );
    }
    for (final l in _lilies) {
      _drawLilyPad(canvas, l);
    }
    canvas.restore();

    canvas.drawPath(water, Paint()
      ..style = PaintingStyle.stroke
      ..strokeWidth = 1.5
      ..color = const Color(0xFF0A3A54).withOpacity(0.4));

    // удочки у занятых секторов (рисуем под маркерами)
    for (final n in _sectorOrder) {
      if (statusByNumber[n] == 'occupied') {
        _drawFishingRod(canvas, _markerPos[n]!, _mapCenter);
      }
    }

    // маркеры
    final tp = TextPainter(textDirection: TextDirection.ltr);
    for (final n in _sectorOrder) {
      final p = _markerPos[n]!;
      final occupied = statusByNumber[n] == 'occupied';
      final color = occupied ? _orange : _green;
      final isSelected = selected == n;
      final r = isSelected ? _markerR * 1.22 : _markerR;

      // Тень
      canvas.drawCircle(p.translate(1, 2), r, Paint()..color = Colors.black.withOpacity(0.12));

      // Мягкое свечение (заливка, не рамка)
      if (isSelected) {
        canvas.drawCircle(p, r + 5, Paint()..color = Colors.white.withOpacity(0.18));
      }

      // Заливка маркера
      canvas.drawCircle(p, r, Paint()..color = color);

      // Единая белая рамка
      canvas.drawCircle(p, r,
        Paint()..style = PaintingStyle.stroke..strokeWidth = isSelected ? 3.5 : 2.5
          ..color = Colors.white);

      // Номер сектора
      tp.text = TextSpan(text: '$n',
        style: TextStyle(color: Colors.white, fontWeight: FontWeight.w800,
          fontSize: isSelected ? 22 : 20));
      tp.layout();
      tp.paint(canvas, Offset(p.dx - tp.width / 2, p.dy - tp.height / 2));
    }

    canvas.restore();
  }

  // ── Кустарник — органичный кластер кругов (как Bush в референсе) ──
  void _drawBush(Canvas canvas, Offset o, double s, int tone) {
    const darkTones = [Color(0xFF2E5C38), Color(0xFF3B6E42), Color(0xFF356749)];
    const midTones = [Color(0xFF4C8A58), Color(0xFF57935F), Color(0xFF4E8A5A)];
    final dark = darkTones[tone % 3], mid = midTones[tone % 3];
    canvas.save();
    canvas.translate(o.dx, o.dy);
    canvas.scale(s);
    canvas.drawOval(Rect.fromCenter(center: const Offset(0, 10), width: 68, height: 18),
      Paint()..color = Colors.black.withOpacity(0.10));
    canvas.drawCircle(const Offset(-16, 0), 17, Paint()..color = dark);
    canvas.drawCircle(const Offset(10, -6), 20, Paint()..color = mid);
    canvas.drawCircle(const Offset(20, 6), 14, Paint()..color = dark);
    canvas.drawCircle(const Offset(-2, 8), 15, Paint()..color = mid);
    canvas.drawCircle(const Offset(4, -10), 10, Paint()..color = const Color(0xFF63A468).withOpacity(0.85));
    canvas.restore();
  }

  // ── Тростник — пучок стеблей ──
  void _drawReedTuft(Canvas canvas, Offset o, double s) {
    canvas.save();
    canvas.translate(o.dx, o.dy);
    canvas.scale(s);
    final p = Paint()
      ..style = PaintingStyle.stroke
      ..strokeWidth = 2.4
      ..strokeCap = StrokeCap.round
      ..color = const Color(0xFF3C6B34);
    Path stem(Offset c1, Offset end) {
      final path = Path()..moveTo(0, 0);
      path.quadraticBezierTo(c1.dx, c1.dy, end.dx, end.dy);
      return path;
    }
    canvas.drawPath(stem(const Offset(-2, -18), const Offset(-10, -40)), p);
    canvas.drawPath(stem(const Offset(5, -22), const Offset(2, -46)), p);
    canvas.drawPath(stem(const Offset(12, -16), const Offset(22, -34)), p);
    canvas.drawPath(stem(const Offset(-8, -14), const Offset(-20, -28)), p);
    canvas.drawCircle(const Offset(2, -46), 2.6, Paint()..color = const Color(0xFF6B5A2E));
    canvas.restore();
  }

  // ── Лилия на воде ──
  void _drawLilyPad(Canvas canvas, _Lily l) {
    canvas.save();
    canvas.translate(l.x, l.y);
    canvas.drawOval(Rect.fromCenter(center: const Offset(1.5, 2), width: l.r * 2, height: l.r * 1.24),
      Paint()..color = const Color(0xFF0E3A50).withOpacity(0.35));
    canvas.save();
    canvas.rotate(18 * math.pi / 180);
    canvas.drawCircle(Offset.zero, l.r, Paint()..color = const Color(0xFF3E8F52));
    canvas.drawLine(Offset.zero, Offset(l.r * 0.85, 0),
      Paint()..strokeWidth = 1.4..color = const Color(0xFF2C6B3C).withOpacity(0.6));
    canvas.restore();
    if (l.r > 11) {
      canvas.drawCircle(Offset(-l.r * 0.15, -l.r * 0.05), l.r * 0.16,
        Paint()..color = const Color(0xFFF4E3E8).withOpacity(0.9));
    }
    canvas.restore();
  }

  // ── Удочка у занятого сектора: удилище + леска + поплавок с рябью ──
  void _drawFishingRod(Canvas canvas, Offset marker, Offset center) {
    final dx = center.dx - marker.dx, dy = center.dy - marker.dy;
    final len = math.sqrt(dx * dx + dy * dy);
    if (len == 0) return;
    final ux = dx / len, uy = dy / len;
    final bank = marker + Offset(ux, uy) * (_markerR + 6);
    final tip = marker + Offset(ux, uy) * (_markerR + 26) + Offset(-uy, ux) * 10 + const Offset(0, -14);
    final float = marker + Offset(ux, uy) * (len * 0.4);

    canvas.drawLine(bank, tip,
      Paint()..strokeWidth = 2.4..strokeCap = StrokeCap.round..color = const Color(0xFF7A5533));
    canvas.drawLine(tip, float,
      Paint()..strokeWidth = 1..color = const Color(0xFFEDE6D6).withOpacity(0.85));
    canvas.drawCircle(float, 9, Paint()
      ..style = PaintingStyle.stroke..strokeWidth = 1..color = const Color(0xFFDCEFF6).withOpacity(0.35));
    canvas.drawCircle(float, 14, Paint()
      ..style = PaintingStyle.stroke..strokeWidth = 1..color = const Color(0xFFDCEFF6).withOpacity(0.2));
    canvas.drawCircle(float, 3.6, Paint()..color = Colors.white);
    canvas.drawArc(Rect.fromCircle(center: float, radius: 3.6), math.pi, math.pi, true,
      Paint()..color = const Color(0xFFD6412E));
  }

  List<Offset> _offsetPoints(double offset) {
    return _sectorOrder.map((n) {
      final p = _markerPos[n]!;
      final dx = p.dx - _mapCenter.dx, dy = p.dy - _mapCenter.dy;
      final len = math.sqrt(dx * dx + dy * dy);
      final k = len == 0 ? 0 : offset / len;
      return Offset(p.dx + dx * k, p.dy + dy * k);
    }).toList();
  }

  Path _catmullRomPath(List<Offset> pts) {
    final n = pts.length;
    final path = Path()..moveTo(pts[0].dx, pts[0].dy);
    for (var i = 0; i < n; i++) {
      final p0 = pts[(i - 1 + n) % n], p1 = pts[i], p2 = pts[(i + 1) % n], p3 = pts[(i + 2) % n];
      final c1x = p1.dx + (p2.dx - p0.dx) / 6, c1y = p1.dy + (p2.dy - p0.dy) / 6;
      final c2x = p2.dx - (p3.dx - p1.dx) / 6, c2y = p2.dy - (p3.dy - p1.dy) / 6;
      path.cubicTo(c1x, c1y, c2x, c2y, p2.dx, p2.dy);
    }
    return path..close();
  }

  @override
  bool shouldRepaint(covariant _PondPainter old) =>
      old.statusByNumber != statusByNumber ||
      old.selected != selected ||
      old.treeImages != treeImages ||
      old.grassTile != grassTile;
}

// ─────────────────────────── Виджет карты ───────────────────────────
class PondMapView extends StatefulWidget {
  final List<Map<String, dynamic>> sectorStatuses; // [{number, status}]
  final int? selected;
  final ValueChanged<int> onTap;
  const PondMapView({super.key, required this.sectorStatuses, required this.selected, required this.onTap});
  @override
  State<PondMapView> createState() => _PondMapViewState();
}

class _PondMapViewState extends State<PondMapView> {
  final List<ui.Image?> _trees = List<ui.Image?>.filled(4, null);
  ui.Image? _grassTile;

  @override
  void initState() {
    super.initState();
    _loadImages();
  }

  Future<ui.Image> _decode(String b64) async {
    final bytes = base64Decode(b64);
    final codec = await ui.instantiateImageCodec(bytes);
    final frame = await codec.getNextFrame();
    return frame.image;
  }

  Future<void> _loadImages() async {
    final results = await Future.wait([
      _decode(kTreeMainB64),
      _decode(kTreeExtra0B64),
      _decode(kTreeExtra1B64),
      _decode(kTreeExtra2B64),
      _decode(kGrassTileB64),
    ]);
    if (!mounted) return;
    setState(() {
      _trees[0] = results[0];
      _trees[1] = results[1];
      _trees[2] = results[2];
      _trees[3] = results[3];
      _grassTile = results[4];
    });
  }

  @override
  Widget build(BuildContext context) {
    final map = {for (final s in widget.sectorStatuses) s['number'] as int: s['status'] as String};
    return LayoutBuilder(builder: (ctx, c) {
      final w = c.maxWidth;
      final h = w * _fullH / _fullW;
      return GestureDetector(
        onTapDown: (d) {
          final scale = w / _fullW;
          final tapX = d.localPosition.dx / scale - _margin;
          final tapY = d.localPosition.dy / scale - _margin;
          for (final n in _sectorOrder) {
            final p = _markerPos[n]!;
            if ((tapX - p.dx) * (tapX - p.dx) + (tapY - p.dy) * (tapY - p.dy) <= _markerR * _markerR) {
              widget.onTap(n);
              break;
            }
          }
        },
        child: ClipRRect(
          borderRadius: BorderRadius.circular(26),
          child: SizedBox(
            width: w, height: h,
            child: CustomPaint(painter: _PondPainter(
              statusByNumber: map, selected: widget.selected, treeImages: _trees, grassTile: _grassTile)),
          ),
        ),
      );
    });
  }
}

