// ─────────────────────────── Фильтр (Правка 1.2) ───────────────────────────


class FiltersDropdown extends StatefulWidget {
  final FilterValue value;
  final ValueChanged<FilterValue> onChange;
  const FiltersDropdown({super.key, required this.value, required this.onChange});

  @override
  State<FiltersDropdown> createState() => _FiltersDropdownState();
}

class _FiltersDropdownState extends State<FiltersDropdown> {
  final LayerLink _layerLink = LayerLink();
  OverlayEntry? _overlayEntry;
  bool _isOpen = false;

  // Ширина dropdown = ширина кнопки фильтров; зазор = 0 (без отрыва)
  static const double _itemHeight = kDropdownItemHeight;
  static const double _dropdownVPadding = kDropdownVPadding;
  static const double _gap = kDropdownGap;

  void _toggleDropdown() {
    if (_isOpen) {
      _closeDropdown();
    } else {
      _openDropdown();
    }
  }

  void _openDropdown() {
    setState(() => _isOpen = true);
    _overlayEntry = _createOverlayEntry();
    Overlay.of(context).insert(_overlayEntry!);
  }

  void _closeDropdown() {
    _overlayEntry?.remove();
    _overlayEntry = null;
    if (mounted) setState(() => _isOpen = false);
  }

  OverlayEntry _createOverlayEntry() {
    final rb = context.findRenderObject() as RenderBox;
    final btnSize = rb.size;
    final btnPos = rb.localToGlobal(Offset.zero);

    const double _overlap = 12.0; // перекрываем нижние скруглённые углы кнопки
    final dropdownW = btnSize.width;

    final dy = btnSize.height - _overlap;

    // MediaQuery берём ЗДЕСЬ (в контексте виджета, не overlay) —
    // иначе значения могут быть неверными.
    final screenH = MediaQuery.of(context).size.height;
    final bottomSafe = MediaQuery.of(context).padding.bottom;
    // dropdown nachinaetsya na _overlap vyshe btnBottomY
    // rawH rasschitan ot btnBottomY -> dobavlyaem _overlap chtoby dropdown byl vyshe
    // no nizhniy kraj ostaetsya na meste (ne zalezayet na bottomNav)
    final maxDropdownH = calcMaxDropdownHeight(
      btnBottomY: btnPos.dy + btnSize.height,
      screenH: screenH,
      bottomPadding: bottomSafe,
    ) + _overlap;

    return OverlayEntry(
      builder: (overlayContext) => GestureDetector(
        behavior: HitTestBehavior.translucent,
        onTap: _closeDropdown,
        child: Stack(children: [
          Positioned.fill(
            child: Container(color: Colors.transparent),
          ),
          Positioned(
            width: dropdownW,
            child: CompositedTransformFollower(
              link: _layerLink,
              showWhenUnlinked: false,
              offset: Offset(0, dy),
              child: ConstrainedBox(
                constraints: BoxConstraints(maxHeight: maxDropdownH > 100 ? maxDropdownH : 100),
                child: Material(
                  elevation: 0,
                  borderRadius: const BorderRadius.only(
                    bottomLeft: Radius.circular(14),
                    bottomRight: Radius.circular(14),
                  ),
                  color: Colors.white,
                  child: Container(
                    decoration: const BoxDecoration(
                      color: Colors.white,
                      borderRadius: BorderRadius.only(
                        bottomLeft: Radius.circular(14),
                        bottomRight: Radius.circular(14),
                      ),
                    ),
                    child: ClipRRect(
                      borderRadius: const BorderRadius.only(
                        bottomLeft: Radius.circular(14),
                        bottomRight: Radius.circular(14),
                      ),
                      child: SingleChildScrollView(
                        padding: const EdgeInsets.symmetric(vertical: _dropdownVPadding),
                        child: Column(mainAxisSize: MainAxisSize.min, children: [
                        ...filterOptions.entries.map((e) {
                          final isSelected = widget.value == e.key;
                          return InkWell(
                            onTap: () {
                              widget.onChange(e.key);
                              _closeDropdown();
                            },
                            child: Container(
                              width: double.infinity,
                              padding: const EdgeInsets.symmetric(horizontal: 14, vertical: 12),
                              color: isSelected ? const Color(0xFFF5EEDC) : Colors.transparent,
                              child: Text(e.value,
                                style: TextStyle(fontSize: 13, color: _ink,
                                  fontWeight: isSelected ? FontWeight.w700 : FontWeight.w400)),
                            ),
                          );
                        }),
                      ]),
                    ),
                  ),
                ),
              ),
            ),
          ),
          ),
        ]),
      ),
    );
  }

  @override
  void dispose() {
    _overlayEntry?.remove();
    _overlayEntry = null;
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    const pill = BorderRadius.all(Radius.circular(999));

    return CompositedTransformTarget(
      link: _layerLink,
      child: GestureDetector(
        onTap: _toggleDropdown,
        child: Container(
          width: 120,
          padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 8),
          decoration: const BoxDecoration(
            color: Colors.white,
            borderRadius: BorderRadius.all(Radius.circular(999)),
          ),
          child: Row(children: [
            const Icon(Icons.filter_list, size: 13, color: _ember),
            const SizedBox(width: 6),
            Flexible(
              child: Text(filterButtonLabels[widget.value]!,
                overflow: TextOverflow.ellipsis, maxLines: 1,
                style: const TextStyle(fontSize: 12.5, fontWeight: FontWeight.w700, color: _ink)),
            ),
          ]),
        ),
      ),
    );
  }
}

bool passesFilter(Slot s, FilterValue f) {
  if (f == FilterValue.none) return true;
  if (f == FilterValue.all) return s.client != null;
  final level = f == FilterValue.premium ? LevelKey.premium
      : f == FilterValue.standard ? LevelKey.standard : LevelKey.basic;
  return s.client != null && s.client!.level == level;
}

// ─────────────────────────── Экран целиком ───────────────────────────
class PondMapScreen extends StatefulWidget {
  const PondMapScreen({super.key});
  @override
  State<PondMapScreen> createState() => _PondMapScreenState();
}

class _PondMapScreenState extends State<PondMapScreen> {
  DateTime date = DateTime(2026, 7, 12);
  int hour = 6;
  int? selected;
  FilterValue filter = FilterValue.none;

  List<List<Slot>> get schedules =>
      List.generate(16, (i) => _scheduleFor(date, i + 1));

  @override
  Widget build(BuildContext context) {
    final scheds = schedules;
    final statuses = List.generate(16, (i) => {
      'number': i + 1, 'status': _statusAtHour(scheds[i], hour),
    });
    final occupied = statuses.where((s) => s['status'] == 'occupied').length;
    final free = 16 - occupied;
    final load = ((occupied / 16) * 100).round();

    return Scaffold(
      backgroundColor: const Color(0xFFEFE9DC),
      body: SafeArea(child: Column(children: [
        Expanded(child: ListView(padding: const EdgeInsets.fromLTRB(20, 0, 20, 24), children: [
          // Заголовок
          const Padding(
            padding: EdgeInsets.fromLTRB(0, 12, 0, 12),
            child: Center(child: Text('Карта пруда',
              style: TextStyle(fontSize: 22, fontWeight: FontWeight.w800, color: _ink))),
          ),
          // Chips
          Row(children: [
            Expanded(child: _chip(Icons.calendar_today_outlined, 'ДАТА',
              '${date.day} ${_monthsShort[date.month - 1]}',
              onTap: () async {
                final picked = await _showCalendarPicker(context, date);
                if (picked != null) setState(() { date = picked; selected = null; });
              })),
            const SizedBox(width: 8),
            Expanded(child: _chip(Icons.access_time, 'ВРЕМЯ', _fmt(hour),
              onTap: () async {
                final picked = await showDialog<int>(
                  context: context,
                  barrierColor: const Color(0x7314130F),
                  builder: (_) => _TimePicker(hour: hour));
                if (picked != null) setState(() { hour = picked; selected = null; });
              })),
          ]),
          const SizedBox(height: 14),
          Row(children: [
            Expanded(child: _statCard(dark: true, label: 'ЗАГРУЗКА', value: '$load%', valueColor: _orange)),
            const SizedBox(width: 10),
            Expanded(child: _statCard(dark: false, label: 'БРОНЕЙ', value: '$occupied / 16', valueColor: _ink)),
          ]),
          const SizedBox(height: 12),
          PondMapView(sectorStatuses: statuses, selected: selected,
            onTap: (n) => setState(() => selected = selected == n ? null : n)),
          const SizedBox(height: 16),
          Row(children: [
            FiltersDropdown(value: filter, onChange: (v) => setState(() => filter = v)),
            const Spacer(),
            _legend(_green, 'Свободно $free'),
            const SizedBox(width: 12),
            _legend(_orange, 'Занято $occupied'),
          ]),
          const SizedBox(height: 12),
          Text(
            selected != null
                ? 'РАСПИСАНИЕ · СЕКТОР № ${selected!.toString().padLeft(2, '0')}'
                : 'ЛЕНТА БРОНИРОВАНИЙ НА ПРУДУ',
            style: const TextStyle(fontSize: 11, fontWeight: FontWeight.w700, color: Colors.black45, letterSpacing: 0.4),
          ),
          const SizedBox(height: 8),
          _buildFeed(scheds),
        ])),
      ])),
    );
  }

  Widget _buildFeed(List<List<Slot>> scheds) {
    final rows = <Widget>[];
    for (final block in _blocks) {
      final idx = _blocks.indexOf(block);
      if (selected != null) {
        final s = scheds[selected! - 1][idx];
        if (passesFilter(s, filter)) rows.add(_feedRow(block, selected!, s));
      } else {
        final items = <MapEntry<int, Slot>>[];
        for (var i = 0; i < 16; i++) {
          final s = scheds[i][idx];
          if (passesFilter(s, filter)) items.add(MapEntry(i + 1, s));
        }
        if (items.isEmpty) continue;
        final occ = items.where((e) => e.value.client != null).length;
        rows.add(_groupHeader(block, occ, items.length));
        rows.addAll(items.map((e) => _feedRow(block, e.key, e.value)));
      }
    }
    if (rows.isEmpty) {
      return Container(padding: const EdgeInsets.all(16),
        decoration: BoxDecoration(color: Colors.white, borderRadius: BorderRadius.circular(18),
          border: Border.all(color: _hairline)),
        child: const Text('Нет слотов, подходящих под выбранный фильтр.',
          style: TextStyle(fontSize: 13, color: Colors.black45)));
    }
    return Container(
      decoration: BoxDecoration(color: Colors.white, borderRadius: BorderRadius.circular(18),
        border: Border.all(color: _hairline)),
      child: ClipRRect(borderRadius: BorderRadius.circular(18), child: Column(children: rows)),
    );
  }

  Widget _groupHeader(List<int> block, int occ, int total) => Container(
    padding: const EdgeInsets.symmetric(horizontal: 14, vertical: 9),
    color: const Color(0xFFF5EEDC),
    child: Row(mainAxisAlignment: MainAxisAlignment.spaceBetween, children: [
      Text('${_fmt(block[0])}–${_fmt(block[1])}',
        style: const TextStyle(fontSize: 12.5, fontWeight: FontWeight.w800, color: _ink)),
      Text.rich(TextSpan(children: [
        TextSpan(text: '${total - occ} своб.', style: const TextStyle(color: _green, fontSize: 11, fontWeight: FontWeight.w600)),
        const TextSpan(text: ' · ', style: TextStyle(color: Colors.black45, fontSize: 11)),
        TextSpan(text: '$occ занято', style: const TextStyle(color: _orange, fontSize: 11, fontWeight: FontWeight.w600)),
      ])),
    ]),
  );

  Widget _feedRow(List<int> block, int sector, Slot s) {
    final occupied = s.client != null;
    return Container(
      padding: const EdgeInsets.symmetric(horizontal: 14, vertical: 10),
      decoration: const BoxDecoration(border: Border(top: BorderSide(color: _hairline))),
      child: Row(children: [
        SizedBox(width: 46, child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
          Text(_fmt(block[0]), style: const TextStyle(fontSize: 12.5, fontWeight: FontWeight.w800, color: _ink)),
          Text(_fmt(block[1]), style: const TextStyle(fontSize: 11, fontWeight: FontWeight.w600, color: Colors.black38)),
        ])),
        const SizedBox(width: 10),
        Container(width: 26, height: 26, alignment: Alignment.center,
          decoration: BoxDecoration(color: occupied ? _orange : _green,
            borderRadius: BorderRadius.circular(8)),
          child: Text('$sector', style: const TextStyle(color: Colors.white, fontSize: 11, fontWeight: FontWeight.w800))),
        const SizedBox(width: 10),
        Expanded(child: occupied
          ? InkWell(onTap: () => showClientCard(context, s.client!), child: Row(children: [
              _avatar(s.client!, 32),
              const SizedBox(width: 9),
              Flexible(child: Text(s.client!.name, overflow: TextOverflow.ellipsis,
                style: const TextStyle(fontSize: 13, fontWeight: FontWeight.w700, color: _ink))),
              const SizedBox(width: 6),
              LevelBadge(level: s.client!.level, compact: true),
            ]))
          : const Text('Свободно',
              style: TextStyle(fontSize: 13, fontWeight: FontWeight.w700, color: _green))),
      ]),
    );
  }

  Widget _avatar(Client c, double size) {
    final initials = c.name.split(' ').map((p) => p.isEmpty ? '' : p[0]).take(2).join();
    if (c.avatarAsset != null) {
      return ClipOval(
        child: Image.asset(
          c.avatarAsset!,
          width: size, height: size, fit: BoxFit.cover,
          // Если файл аватара вдруг отсутствует — не роняем экран, а
          // откатываемся на цветной кружок с инициалами.
          errorBuilder: (_, __, ___) => Container(width: size, height: size, alignment: Alignment.center,
            decoration: BoxDecoration(color: c.color, shape: BoxShape.circle),
            child: Text(initials, style: TextStyle(color: Colors.white, fontSize: size * 0.4, fontWeight: FontWeight.w800))),
        ),
      );
    }
    return Container(width: size, height: size, alignment: Alignment.center,
      decoration: BoxDecoration(color: c.color, shape: BoxShape.circle),
      child: Text(initials, style: TextStyle(color: Colors.white, fontSize: size * 0.4, fontWeight: FontWeight.w800)));
  }

  Widget _chip(IconData icon, String caption, String label, {required VoidCallback onTap}) => InkWell(
    onTap: onTap, borderRadius: BorderRadius.circular(16),
    child: Container(
      padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 9),
      decoration: BoxDecoration(
        gradient: const LinearGradient(begin: Alignment.topCenter, end: Alignment.bottomCenter,
          colors: [Colors.white, Color(0xFFFBF7EC)]),
        borderRadius: BorderRadius.circular(16),
        border: Border.all(color: _hairline),
      ),
      child: Row(children: [
        Container(width: 30, height: 30, alignment: Alignment.center,
          decoration: BoxDecoration(color: _ember.withOpacity(0.12), borderRadius: BorderRadius.circular(10)),
          child: Icon(icon, size: 15, color: _ember)),
        const SizedBox(width: 10),
        Expanded(child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
          Text(caption, style: const TextStyle(fontSize: 9.5, fontWeight: FontWeight.w700, color: Colors.black38, letterSpacing: 0.5)),
          Text(label, style: const TextStyle(fontSize: 14, fontWeight: FontWeight.w800, color: _ink)),
        ])),
        const Icon(Icons.expand_more, size: 13, color: Colors.black38),
      ]),
    ),
  );

  Widget _statCard({required bool dark, required String label, required String value, required Color valueColor}) => Container(
    padding: const EdgeInsets.fromLTRB(16, 16, 16, 15),
    decoration: BoxDecoration(
      gradient: LinearGradient(begin: Alignment.topLeft, end: Alignment.bottomRight,
        colors: dark ? const [Color(0xFF1F1D18), _ink] : const [Colors.white, Color(0xFFFCFAF4)]),
      borderRadius: BorderRadius.circular(18),
      border: Border.all(color: dark ? Colors.white10 : _hairline),
    ),
    child: Column(crossAxisAlignment: CrossAxisAlignment.stretch, children: [
      Row(children: [
        Container(width: 22, height: 22, alignment: Alignment.center,
          decoration: BoxDecoration(color: dark ? Colors.white10 : _ember.withOpacity(0.10),
            borderRadius: BorderRadius.circular(7)),
          child: Icon(dark ? Icons.bar_chart : Icons.calendar_today_outlined, size: 13,
            color: dark ? _orange : _ember)),
        const SizedBox(width: 6),
        Text(label, style: TextStyle(fontSize: 10.5, fontWeight: FontWeight.w700, letterSpacing: 0.5,
          color: dark ? Colors.white54 : Colors.black45)),
      ]),
      const SizedBox(height: 10),
      Center(child: Text(value, style: TextStyle(fontSize: 26, fontWeight: FontWeight.w800, color: valueColor))),
    ]),
  );

  Widget _legend(Color color, String text) => Row(mainAxisSize: MainAxisSize.min, children: [
    Container(width: 8, height: 8, decoration: BoxDecoration(color: color, shape: BoxShape.circle)),
    const SizedBox(width: 6),
    Text(text, style: const TextStyle(fontSize: 13, color: _ink)),
  ]);
}

// ─────────────────────────── Календарь (с кнопкой «Применить») ───────────────────────────
// Полный аналог CalendarModal из веб-референса (pond-map-preview-3.tsx):
// центрированная карточка 300×auto на затемнённом фоне, пагинация по месяцам
// круглыми стрелками, сетка дней с оранжевым кружком на выбранном дне,
// применение — только по кнопке «Применить» (выбор дня лишь меняет pending-превью).
Future<DateTime?> _showCalendarPicker(BuildContext context, DateTime date) {
  return showDialog<DateTime>(
    context: context,
    barrierColor: const Color(0x7314130F), // rgba(20,19,15,0.45)
    builder: (_) => _CalendarPicker(date: date),
  );
}

class _CalendarPicker extends StatefulWidget {
  final DateTime date;
  const _CalendarPicker({required this.date});
  @override
  State<_CalendarPicker> createState() => _CalendarPickerState();
}

class _CalendarPickerState extends State<_CalendarPicker> {
  late DateTime cursor = DateTime(widget.date.year, widget.date.month, 1);
  late DateTime pending = widget.date;

  @override
  Widget build(BuildContext context) {
    // Пн=0 … Вс=6 — как (date.getDay() + 6) % 7 в веб-версии
    // (DateTime.weekday: Пн=1 … Вс=7).
    final firstWeekday = (DateTime(cursor.year, cursor.month, 1).weekday - 1) % 7;
    final daysInMonth = DateTime(cursor.year, cursor.month + 1, 0).day;
    final cells = <int?>[
      ...List<int?>.filled(firstWeekday, null),
      ...List.generate(daysInMonth, (i) => i + 1),
    ];

    return Dialog(
      backgroundColor: Colors.transparent,
      elevation: 0,
      insetPadding: const EdgeInsets.symmetric(horizontal: 24),
      child: Container(
        width: 300,
        padding: const EdgeInsets.all(16),
        decoration: BoxDecoration(
          color: _paper,
          borderRadius: BorderRadius.circular(20),
          boxShadow: const [BoxShadow(color: Color(0x4D000000), blurRadius: 50, offset: Offset(0, 20))],
        ),
        child: Column(mainAxisSize: MainAxisSize.min, children: [
          Row(mainAxisAlignment: MainAxisAlignment.spaceBetween, children: [
            _navButton(Icons.chevron_left, () => setState(() {
              cursor = DateTime(cursor.year, cursor.month - 1, 1);
            })),
            Text('${_monthsFull[cursor.month - 1]} ${cursor.year}',
              style: const TextStyle(fontWeight: FontWeight.w800, fontSize: 15, color: _ink)),
            _navButton(Icons.chevron_right, () => setState(() {
              cursor = DateTime(cursor.year, cursor.month + 1, 1);
            })),
          ]),
          const SizedBox(height: 12),
          Row(children: _weekdays.map((w) => Expanded(
            child: Center(child: Text(w,
              style: const TextStyle(fontSize: 11, fontWeight: FontWeight.w700, color: Colors.black38))),
          )).toList()),
          const SizedBox(height: 6),
          GridView.count(
            crossAxisCount: 7, shrinkWrap: true, physics: const NeverScrollableScrollPhysics(),
            mainAxisSpacing: 4, crossAxisSpacing: 4, childAspectRatio: 1,
            children: cells.map((d) {
              if (d == null) return const SizedBox.shrink();
              final isSelected = pending.year == cursor.year &&
                  pending.month == cursor.month && pending.day == d;
              return InkWell(
                customBorder: const CircleBorder(),
                onTap: () => setState(() => pending = DateTime(cursor.year, cursor.month, d)),
                child: Container(
                  alignment: Alignment.center,
                  decoration: BoxDecoration(
                    color: isSelected ? _orange : Colors.transparent,
                    shape: BoxShape.circle,
                  ),
                  child: Text('$d', style: TextStyle(
                    fontSize: 13,
                    fontWeight: isSelected ? FontWeight.w800 : FontWeight.w500,
                    color: isSelected ? Colors.white : _ink,
                  )),
                ),
              );
            }).toList(),
          ),
          const SizedBox(height: 14),
          SizedBox(width: double.infinity, child: FilledButton(
            onPressed: () => Navigator.pop(context, pending),
            style: FilledButton.styleFrom(backgroundColor: _orange, foregroundColor: Colors.white,
              shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(12)),
              padding: const EdgeInsets.symmetric(vertical: 12)),
            child: const Text('Применить', style: TextStyle(fontSize: 14, fontWeight: FontWeight.w700)))),
        ]),
      ),
    );
  }

  Widget _navButton(IconData icon, VoidCallback onTap) => InkWell(
    customBorder: const CircleBorder(),
    onTap: onTap,
    child: Container(
      width: 30, height: 30, alignment: Alignment.center,
      decoration: BoxDecoration(
        color: Colors.white,
        shape: BoxShape.circle,
        border: Border.all(color: _hairline),
      ),
      child: Icon(icon, size: 15, color: _ink),
    ),
  );
}

